/**
 * Generic portal user provisioning for any tenant.
 *
 * Closes the chassis "create client → welcome email → login" gap that was
 * previously CPR-specific (`/api/portal/create-client`). Tenant-agnostic:
 * pass a `TenantConfig` and a user, get back a record + login credentials,
 * with welcome email and admin notification handled.
 */

import { airtableCreate, airtableGet } from './airtable-client';
import { sendEmail } from './resend-client';
import { notifyAdmin } from './admin-notify';
import { triggerMakeWebhook } from './make-client';
import { hashPassword, generateTempPassword } from './passwords';
import type { TenantConfig } from '../config/tenant';

export interface ProvisionPortalUserInput {
  /** Tenant the user belongs to — drives brand, Airtable, and login URL. */
  tenant: TenantConfig;
  email: string;
  name: string;
  /** Logical role, e.g. "parent" | "athlete" | "member" | "client". */
  role?: string;
  /** URL-safe identity slug. Generated from name/email when omitted. */
  slug?: string;
  /** Logical table key in `tenant.airtable.tables`, or a literal table name. */
  table?: string;
  /** Extra Airtable fields merged into the created record. */
  fields?: Record<string, unknown>;
  /** Supply to set a known password; otherwise a temp password is generated. */
  password?: string;
  /** Default true. Sends the branded welcome email with login details. */
  sendWelcomeEmail?: boolean;
  /** Default true. Emails the tenant admin that a user was provisioned. */
  notifyAdminOnCreate?: boolean;
  /** Default true. Rejects if a record with this email already exists. */
  failIfExists?: boolean;
  /** Path appended to the canonical URL for login. Default "/portal/login". */
  loginPath?: string;
  /** Env var holding a Make webhook URL to fire on provision (optional). */
  welcomeWebhookEnvKey?: string;
}

export interface ProvisionPortalUserResult {
  recordId: string;
  email: string;
  name: string;
  role: string;
  slug: string;
  loginUrl: string;
  /** Present only when the password was generated (deliver securely once). */
  tempPassword?: string;
  welcomeEmailSent: boolean;
  adminNotified: boolean;
  webhookFired: boolean;
}

function slugify(input: string): string {
  return input
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 48);
}

function mapField(tenant: TenantConfig, logical: string): string {
  return tenant.airtable.fieldMap?.[logical] ?? logical;
}

function resolveTable(tenant: TenantConfig, table?: string): string {
  if (!table) {
    const first = Object.values(tenant.airtable.tables)[0];
    if (!first) throw new Error(`provisionPortalUser: tenant "${tenant.id}" has no airtable.tables`);
    return first;
  }
  return tenant.airtable.tables[table] ?? table;
}

function welcomeEmailHtml(args: {
  brandName: string;
  name: string;
  email: string;
  loginUrl: string;
  tempPassword?: string;
  supportEmail: string;
}): string {
  const creds = args.tempPassword
    ? `<p style="margin:0 0 8px"><strong>Email:</strong> ${args.email}</p>
       <p style="margin:0 0 16px"><strong>Temporary password:</strong>
         <code style="background:#f2f2f0;padding:2px 6px;border-radius:4px">${args.tempPassword}</code></p>
       <p style="margin:0 0 16px;color:#555">Please change this password after your first sign-in.</p>`
    : `<p style="margin:0 0 16px"><strong>Email:</strong> ${args.email}</p>`;

  return `
    <div style="font-family:Arial,sans-serif;line-height:1.6;color:#151515;max-width:560px;margin:0 auto;padding:24px">
      <h1 style="font-size:22px;margin:0 0 16px">Welcome to ${args.brandName}, ${args.name}</h1>
      <p style="margin:0 0 16px">Your portal account is ready. Sign in to get started.</p>
      ${creds}
      <p style="margin:0 0 24px">
        <a href="${args.loginUrl}"
           style="display:inline-block;background:#111;color:#fff;text-decoration:none;padding:10px 18px;border-radius:6px">
          Open your portal
        </a>
      </p>
      <p style="margin:0;color:#777;font-size:13px">
        Need help? Contact <a href="mailto:${args.supportEmail}">${args.supportEmail}</a>.
      </p>
    </div>
  `;
}

/**
 * Provision a portal user end-to-end: dedupe, hash credentials, create the
 * Airtable record, send the branded welcome email, notify the admin, and
 * optionally fire a Make webhook. Returns login details for the new user.
 */
export async function provisionPortalUser(
  input: ProvisionPortalUserInput,
): Promise<ProvisionPortalUserResult> {
  const {
    tenant,
    email,
    name,
    role = 'member',
    sendWelcomeEmail = true,
    notifyAdminOnCreate = true,
    failIfExists = true,
    loginPath = '/portal/login',
  } = input;

  const normalizedEmail = email.trim().toLowerCase();
  if (!normalizedEmail || !normalizedEmail.includes('@')) {
    throw new Error('provisionPortalUser: a valid email is required');
  }
  if (!name.trim()) throw new Error('provisionPortalUser: name is required');

  const baseId = tenant.airtable.baseId;
  if (!baseId) throw new Error(`provisionPortalUser: tenant "${tenant.id}" has no airtable.baseId`);

  const tableId = resolveTable(tenant, input.table);
  const emailField = mapField(tenant, 'Email');

  if (failIfExists) {
    const escaped = normalizedEmail.replace(/'/g, "\\'");
    const existing = await airtableGet(baseId, tableId, {
      filterByFormula: `LOWER({${emailField}}) = '${escaped}'`,
      maxRecords: 1,
    });
    if (existing.length > 0) {
      throw new Error(`provisionPortalUser: a user with email ${normalizedEmail} already exists`);
    }
  }

  const slug = input.slug ? slugify(input.slug) : slugify(name) || slugify(normalizedEmail);
  const generated = !input.password;
  const password = input.password ?? generateTempPassword();
  const passwordHash = await hashPassword(password);

  const record = await airtableCreate(baseId, tableId, {
    [mapField(tenant, 'Name')]: name.trim(),
    [emailField]: normalizedEmail,
    [mapField(tenant, 'Role')]: role,
    [mapField(tenant, 'Slug')]: slug,
    [mapField(tenant, 'PasswordHash')]: passwordHash,
    [mapField(tenant, 'Status')]: 'active',
    [mapField(tenant, 'CreatedAt')]: new Date().toISOString(),
    ...input.fields,
  });

  const canonical = tenant.urls.canonical.replace(/\/+$/, '');
  const loginUrl = `${canonical}${loginPath.startsWith('/') ? loginPath : `/${loginPath}`}`;

  let welcomeEmailSent = false;
  if (sendWelcomeEmail) {
    try {
      await sendEmail({
        to: normalizedEmail,
        from: tenant.brand.fromEmail,
        subject: `Welcome to ${tenant.brand.name}`,
        html: welcomeEmailHtml({
          brandName: tenant.brand.name,
          name: name.trim(),
          email: normalizedEmail,
          loginUrl,
          tempPassword: generated ? password : undefined,
          supportEmail: tenant.brand.supportEmail,
        }),
      });
      welcomeEmailSent = true;
    } catch (err) {
      console.error('provisionPortalUser: welcome email failed:', err);
    }
  }

  let adminNotified = false;
  if (notifyAdminOnCreate) {
    adminNotified = await notifyAdmin({
      subject: `[${tenant.brand.name}] New portal user: ${name}`,
      title: 'Portal user provisioned',
      bodyHtml: `
        <p><strong>${name}</strong> (${normalizedEmail}) was provisioned as <strong>${role}</strong>.</p>
        <p>Record: ${record.id} · Slug: ${slug}</p>
      `,
      from: tenant.brand.fromEmail,
    });
  }

  let webhookFired = false;
  if (input.welcomeWebhookEnvKey) {
    const url = process.env[input.welcomeWebhookEnvKey]?.trim();
    if (url) {
      const { success } = await triggerMakeWebhook(url, {
        event: 'portal_user_provisioned',
        tenant: tenant.id,
        recordId: record.id,
        email: normalizedEmail,
        name: name.trim(),
        role,
        slug,
      });
      webhookFired = success;
    }
  }

  return {
    recordId: record.id,
    email: normalizedEmail,
    name: name.trim(),
    role,
    slug,
    loginUrl,
    tempPassword: generated ? password : undefined,
    welcomeEmailSent,
    adminNotified,
    webhookFired,
  };
}
